class Node:
    def __init__(self, key):
        self.key = key
        self.left = None
        self.right = None

def insert(root, key):
    if root is None:
        return Node(key)
    if key < root.key:
        root.left = insert(root.left, key)
    elif key > root.key:
        root.right = insert(root.right, key)
    return root

def process_chars_recursive(sequence, index, root, seen):
    if index >= len(sequence):
        return root

    char = sequence[index].lower()
    if char not in seen:
        seen.add(char)
        root = insert(root, char)

    return process_chars_recursive(sequence, index + 1, root, seen)

